records = [
  {"id":"inno_ent_251","name_ja":"ボーングローバル企業","name_en":"Born Global Firms","definition":"創業初期から国際市場を目標とし、設立後2〜3年以内に海外売上が総売上の25%以上を占める企業。Oviattら（1994）が概念化。デジタル製品・SaaS・プラットフォームビジネスでは創業即グローバル（Born Digital Global）が標準化しつつある。従来の段階的国際化理論（Uppsalaモデル）への挑戦として位置づけられる。","impact_summary":"スタートアップの国際化戦略を再定義し、デジタル時代のグローバル起業研究の基盤となった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"国際起業家論","era_start":1994,"schumpeter_layer":"ミクロ","innovation_type":"戦略イノベーション","cognitive_mechanism":"グローバル機会認識とデジタル活用","key_researchers":["Benjamin Oviatt","Patricia McDougall","Marian Jones"],"key_works":["Toward a Theory of International New Ventures (1994)","Born Globals (2005)"],"keywords_ja":"ボーングローバル,国際化,新興企業,デジタルグローバル","keywords_en":"born global,internationalization,new ventures,digital global"},
  {"id":"inno_ent_252","name_ja":"国際起業家精神研究","name_en":"International Entrepreneurship Research","definition":"国境を越えた起業家的機会の認識・評価・活用プロセスを研究する学際領域。McDougall & Oviatt（2000）は「異なる国々からの価値創造」と定義。文化的距離、制度的距離、ネットワーク的紐帯、移民起業家のブリッジング機能が主要研究テーマ。Journal of International Entrepreneurshipが主要学術誌。","impact_summary":"起業家研究と国際ビジネス研究を統合する学際領域を確立し、グローバルスタートアップ研究の学術基盤を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"国際起業家論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"国際化イノベーション","cognitive_mechanism":"文化的・制度的距離の克服","key_researchers":["Patricia McDougall","Benjamin Oviatt","Erkko Autio"],"key_works":["International Entrepreneurship (2000)","The Internationalization of Entrepreneurship (2005)"],"keywords_ja":"国際起業家精神,文化的距離,ボーングローバル,新興市場","keywords_en":"international entrepreneurship,cultural distance,born global,emerging markets"},
  {"id":"inno_ent_253","name_ja":"スタートアップエコシステムランキング","name_en":"Startup Ecosystem Rankings","definition":"Startup Genome、GSER（Global Startup Ecosystem Report）、Compass等が実施する都市・国レベルのスタートアップエコシステム比較評価。パフォーマンス（ユニコーン数・資金調達額）、人材、資金調達、市場アクセス、インフラ、経験・知識の6次元で評価。東京、大阪、福岡等日本都市のランキング推移も政策参照指標として機能している。","impact_summary":"エコシステムの定量評価基準を確立し、都市間・国家間競争を促進するとともに政策優先事項の特定を支援した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":2012,"schumpeter_layer":"メゾ","innovation_type":"測定・政策イノベーション","cognitive_mechanism":"ベンチマーキングによる模倣と改善","key_researchers":["JF Gauthier","Marc Penzel","Startup Genome team"],"key_works":["Global Startup Ecosystem Report (annual)","The Startup Genome Report (2012)"],"keywords_ja":"スタートアップエコシステム,ランキング,GSER,都市比較","keywords_en":"startup ecosystem ranking,GSER,city comparison,benchmarking"},
  {"id":"inno_ent_254","name_ja":"Feld ボルダー・テーゼ","name_en":"Feld Boulder Thesis on Startup Communities","definition":"Brad Feldがボルダー（コロラド州）の経験から抽出した起業家コミュニティ構築の4原則：起業家がリーダーシップ、長期コミットメント（20年）、オープンな参加、継続的活動。大学・政府・VCはFeeder（支援者）であり、起業家自身がコミュニティの核であるべきと主張。「トップダウン型エコシステム政策」への批判として機能した。","impact_summary":"起業家コミュニティ設計の実践的原則を提示し、世界中のエコシステム構築者の参照フレームとなった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":2012,"schumpeter_layer":"メゾ","innovation_type":"コミュニティ設計イノベーション","cognitive_mechanism":"社会的資本蓄積とコミュニティ規範形成","key_researchers":["Brad Feld","Ian Hathaway","Victor Hwang"],"key_works":["Startup Communities (2012)","The Startup Community Way (2020)"],"keywords_ja":"ボルダー・テーゼ,起業家コミュニティ,20年コミット,エコシステム","keywords_en":"Boulder thesis,startup community,20-year commitment,ecosystem building"},
  {"id":"inno_ent_255","name_ja":"スタートアップスタジオモデル","name_en":"Startup Studio Model","definition":"アイデアの体系的生成から事業化までを専門とする組織形態（スタートアップファクトリーとも呼ばれる）。Idealab（Bill Gross、1996）、eFounders、Pioneer Squareが代表例。チーム・技術・資本の共有インフラを活用し、複数のスタートアップを並列的に構築するVCとアクセラレーターの中間形態。GSSN（Global Startup Studio Network）が業界標準化を推進している。","impact_summary":"スタートアップ創出の産業化モデルを提示し、事業開発の体系性と再現性を高める組織形態を確立した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"アクセラレーター論","era_start":1996,"schumpeter_layer":"メゾ","innovation_type":"組織イノベーション","cognitive_mechanism":"並列的仮説生成と共有資源活用","key_researchers":["Bill Gross","Wences Casares","Global Startup Studio Network"],"key_works":["The Startup Studio Playbook (2021)","GSSN Benchmark Report (2019)"],"keywords_ja":"スタートアップスタジオ,Idealab,並列起業,ファクトリーモデル","keywords_en":"startup studio,Idealab,parallel entrepreneurship,factory model"},
  {"id":"inno_ent_256","name_ja":"インパクト投資と起業家精神","name_en":"Impact Investing and Entrepreneurship","definition":"財務リターンと社会・環境的インパクトの両立を目指す投資手法とその起業家精神との関係。GIIN（Global Impact Investing Network）の定義では「意図性（intentionality）」「測定可能性（measurability）」「財務リターン（financial return）」の3要素が必須。Acumen Fund、BRAC等のハイブリッド組織、BCorp認証企業が研究対象。インパクト測定（IRIS+、SROI）の標準化が進む。","impact_summary":"社会課題解決と資本市場の接合を可能にし、社会的起業家の資金調達選択肢を拡大した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"社会的起業家論","era_start":2007,"schumpeter_layer":"メゾ","innovation_type":"金融・社会イノベーション","cognitive_mechanism":"二重目標（財務＋インパクト）のトレードオフ管理","key_researchers":["Jed Emerson","Antony Bugg-Levine","Jacob Gray"],"key_works":["Impact Investing (2011)","GIIN Annual Impact Investor Survey"],"keywords_ja":"インパクト投資,GIIN,SROI,BCorp,社会的起業","keywords_en":"impact investing,GIIN,SROI,BCorp,social entrepreneurship"},
  {"id":"inno_ent_257","name_ja":"プロダクト主導成長（PLG）","name_en":"Product-Led Growth","definition":"セールス・マーケティング費用を最小化し、製品自体がユーザー獲得・活性化・拡大のエンジンとなる成長戦略。Slack、Dropbox、Zoom、Notionが代表事例。フリーミアムモデル、バイラルループ、製品内ネットワーク効果がPLGの基本メカニズム。OpenView Partnersが概念を体系化し、PLG指標（PQL＝Product Qualified Lead）を定義した。","impact_summary":"SaaS・消費者向けソフトウェアの成長モデルを変革し、高CAC（顧客獲得費用）型のSaaS経営からの転換を促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2016,"schumpeter_layer":"ミクロ","innovation_type":"ビジネスモデルイノベーション","cognitive_mechanism":"製品体験による自己伝播と口コミ","key_researchers":["Blake Bartlett","Wes Bush","Elena Verna"],"key_works":["Product-Led Growth (2019)","The Product-Led Growth Collective Reports"],"keywords_ja":"PLG,フリーミアム,SaaS,製品主導,バイラルループ","keywords_en":"PLG,freemium,SaaS,product-led,viral loop"},
  {"id":"inno_ent_258","name_ja":"起業家的マーケティング理論","name_en":"Entrepreneurial Marketing Theory","definition":"大企業マーケティングとは異なる、資源制約下でのスタートアップの市場創造・顧客獲得戦略の研究。Hills & Hultmanによる「起業家的マーケティング」概念：機会志向、直感的判断、インフォーマルなリサーチ、バリューイノベーション。グロースハック（AirbnbのCraigslist活用、Dropboxの紹介プログラム）がケース事例として研究される。","impact_summary":"リソース制約を創造性と機動性で補う中小・ベンチャー企業向けマーケティング理論を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"マーケティング論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"マーケティングイノベーション","cognitive_mechanism":"機会志向とゲリラ的資源活用","key_researchers":["Gerald Hills","Claes Hultman","Marian Jones"],"key_works":["Entrepreneurial Marketing (2008)","Growth Hacker Marketing (2014)"],"keywords_ja":"起業家的マーケティング,グロースハック,機会志向,リソース制約","keywords_en":"entrepreneurial marketing,growth hacking,opportunity orientation,resource constraints"},
  {"id":"inno_ent_259","name_ja":"クリーンテックスタートアップの起業家精神","name_en":"Cleantech Startup Entrepreneurship","definition":"環境・エネルギー問題解決を目的とするクリーンテック（太陽光、風力、EV、省エネ等）スタートアップの起業家精神研究。技術開発サイクルの長さ、資本集約性、政策依存性（補助金・規制）という独自の課題が通常のソフトウェアスタートアップとは異なる経営論理を生む。Cleantech 1.0の崩壊（2008-2012）から学んだTesla、SolarEdge等の成功要因分析が重要。","impact_summary":"気候変動対応技術の商業化に関する起業論的理解を深め、ディープテックスタートアップへの投資論理を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"環境技術イノベーション","cognitive_mechanism":"規制機会とミッション駆動の長期投資","key_researchers":["Matthew Nordan","Rob Day","Sheeraz Haji"],"key_works":["Cleantech Revolution (2007)","Why Cleantech 1.0 Failed (2012)"],"keywords_ja":"クリーンテック,エネルギースタートアップ,ディープテック,政策起業家","keywords_en":"cleantech,energy startup,deep tech,policy entrepreneurship"},
  {"id":"inno_ent_260","name_ja":"ディープテックスタートアップ論","name_en":"Deep Tech Startup Theory","definition":"科学的発見や工学的革新（バイオ、量子コンピュータ、宇宙、ロボティクス等）を基盤とするディープテックスタートアップの独自経営課題を研究する領域。BCG Henderson Institute等が概念化。技術TRL（Technology Readiness Level）の移行コスト、長い開発タイムライン、特殊人材の希少性、大型資本需要が特徴。国防・大学・政府との連携が不可欠。","impact_summary":"ハードウェア・バイオ・宇宙など資本集約型技術起業の独自論理を整理し、投資家・政策立案者の判断基準を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"技術起業家論","era_start":2014,"schumpeter_layer":"ミクロ","innovation_type":"技術起業イノベーション","cognitive_mechanism":"科学的不確実性と商業化タイムラインの管理","key_researchers":["Arnaud de la Tour","BCG Henderson Institute","Pierre Labarthe"],"key_works":["The Dawn of the Deep Tech Ecosystem (2019)","Decoding Deep Tech (2020)"],"keywords_ja":"ディープテック,TRL,量子コンピュータ,宇宙スタートアップ","keywords_en":"deep tech,TRL,quantum computing,space startup"},
  {"id":"inno_ent_261","name_ja":"プラットフォーム起業家精神","name_en":"Platform Entrepreneurship","definition":"マルチサイドプラットフォームを基盤事業とするスタートアップの起業家精神。Uber、Airbnb、TaskRabbit等のギグエコノミープラットフォームが代表例。チキンアンドエッグ問題（鶏と卵の問題）の解決戦略（片側補助、同時起動、ジグザグ戦略等）が研究される。プラットフォームオーナーとサプライヤーの力関係、プラットフォームエンベロップメント、ネットワーク効果の測定が主要テーマ。","impact_summary":"ネットワーク効果に基づく新産業創造のロジックを解明し、シェアリングエコノミーと規制問題の理解を深めた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"プラットフォーム論","era_start":2008,"schumpeter_layer":"ミクロ","innovation_type":"プラットフォームイノベーション","cognitive_mechanism":"多面市場の同時育成と鶏卵問題解決","key_researchers":["Andrei Hagiu","Geoffrey Parker","Marshall Van Alstyne"],"key_works":["Platform Revolution (2016)","Multi-Sided Platforms (2007)"],"keywords_ja":"プラットフォーム起業,鶏卵問題,マルチサイド,ネットワーク効果","keywords_en":"platform entrepreneurship,chicken-egg problem,multi-sided,network effects"},
  {"id":"inno_ent_262","name_ja":"ギグエコノミーと独立起業家精神","name_en":"Gig Economy and Independent Entrepreneurship","definition":"デジタルプラットフォームを通じた単発・短期的な仕事（ギグ）に従事する独立業者の研究。Uber、Lyft、Fiverr、Upworkが代表的プラットフォーム。「自律的就業形態としての解放」対「労働権・社会保障の剥奪」という緊張関係が研究の中心。独立起業家（solopreneur）、フリーランサーの増加とその経済的安定性、キャリア形成が研究される。","impact_summary":"就労形態の多様化と起業家精神の境界溶解を記述し、プラットフォーム労働規制の政策議論に貢献した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"プラットフォーム論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"労働・雇用イノベーション","cognitive_mechanism":"自律性と経済的安定のトレードオフ","key_researchers":["Diane Mulcahy","Vili Lehdonvirta","Alex Rosenblat"],"key_works":["The Gig Economy (2016)","Uberland (2018)"],"keywords_ja":"ギグエコノミー,フリーランス,プラットフォーム労働,独立起業家","keywords_en":"gig economy,freelance,platform labor,independent entrepreneurship"},
  {"id":"inno_ent_263","name_ja":"起業家精神と地域経済発展","name_en":"Entrepreneurship and Regional Economic Development","definition":"地域の起業活動が経済成長・雇用創出・イノベーション拡散に与える影響の研究。Audretsch & Fritschらの「知識スピルオーバー起業家精神理論（KSTE）」は、大学・研究機関の知識が起業チャネルを通じて商業化され地域成長を促すメカニズムを説明した。クラスター・起業率・産業構造の相互作用が分析される。","impact_summary":"起業家精神を地域経済政策の中核変数として位置づけ、大学・産業・地域の連携政策設計に貢献した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"地域起業家論","era_start":2003,"schumpeter_layer":"メゾ","innovation_type":"地域経済イノベーション","cognitive_mechanism":"知識スピルオーバーと地域への起業的埋め込み","key_researchers":["David Audretsch","Michael Fritsch","Zoltan Acs"],"key_works":["Knowledge Spillover Theory of Entrepreneurship (2004)","Entrepreneurship and Economic Growth (2010)"],"keywords_ja":"KSTE,知識スピルオーバー,地域起業,大学発スタートアップ","keywords_en":"KSTE,knowledge spillover,regional entrepreneurship,university spinoff"},
  {"id":"inno_ent_264","name_ja":"大学発スタートアップ研究","name_en":"University Spinoff Research","definition":"大学・研究機関から技術・人材が移転して創業されるスタートアップ（スピンオフ・スピンアウト）の研究。Shane（2004）はMIT技術移転の大規模研究を通じて、技術の質・起業家の経験・VC可用性が成功の鍵と示した。TTO（技術移転オフィス）の役割、株式配分（大学vs発明者vs起業家）、ライセンスvs起業の選択が研究される。","impact_summary":"大学発イノベーションの商業化経路を体系化し、産学連携政策と技術移転制度設計に貢献した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":1980,"schumpeter_layer":"メゾ","innovation_type":"技術移転イノベーション","cognitive_mechanism":"アカデミック起業家の動機と知識商業化","key_researchers":["Scott Shane","Donald Siegel","Mike Wright"],"key_works":["Academic Entrepreneurship (2004)","A General Theory of Entrepreneurship (2003)"],"keywords_ja":"大学発スタートアップ,TTO,技術移転,アカデミック起業家","keywords_en":"university spinoff,TTO,technology transfer,academic entrepreneurship"},
  {"id":"inno_ent_265","name_ja":"Bayh-Dole法と大学起業家精神","name_en":"Bayh-Dole Act and University Entrepreneurship","definition":"1980年米国で制定されたBayh-Dole法（特許・商標改正法）が大学・研究機関の連邦資金研究成果の知財所有権を付与し、大学発スタートアップを急増させた制度変革の研究。MIT、スタンフォード、UCカレッジのTTO設立と特許収入増加が実証され、日本（2004年知財立国法）、EU各国への波及も分析された。","impact_summary":"政府研究費を起業家的イノベーションに転換する制度的仕組みを確立し、世界各国の技術移転政策の参照モデルとなった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"制度的起業家論","era_start":1980,"schumpeter_layer":"メゾ","innovation_type":"制度イノベーション","cognitive_mechanism":"所有権付与による商業化インセンティブ","key_researchers":["David Mowery","Bhaven Sampat","Ashish Arora"],"key_works":["Ivory Tower and Industrial Innovation (2004)","The Bayh-Dole Act at 25 (2006)"],"keywords_ja":"Bayh-Dole法,大学知財,TTO,技術移転政策","keywords_en":"Bayh-Dole Act,university IP,TTO,technology transfer policy"},
  {"id":"inno_ent_266","name_ja":"アントレプレナーシップと制度理論","name_en":"Entrepreneurship and Institutional Theory","definition":"North（1990）の制度経済学を起業家研究に接続し、フォーマル制度（法律・規制）とインフォーマル制度（文化・規範）が起業行動を規定するメカニズムを分析する枠組み。Welter（2011）の「文脈的起業家精神」は企業社会的・地理的・機関的文脈が起業家を形成すると主張。新興市場での制度的空白（institutional voids）への対応が重要テーマ。","impact_summary":"起業家精神の「普遍的モデル」批判を通じ、文脈依存的・制度的視点を研究の主流に押し上げた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"制度的起業家論","era_start":1990,"schumpeter_layer":"メゾ","innovation_type":"制度イノベーション","cognitive_mechanism":"制度的文脈への適応と制度変革の起業家的力","key_researchers":["Friederike Welter","Douglass North","Johanna Mair"],"key_works":["Contextualizing Entrepreneurship (2011)","Institutions (1990)"],"keywords_ja":"制度理論,起業家精神,文脈,制度的空白,新興市場","keywords_en":"institutional theory,entrepreneurship,context,institutional voids,emerging markets"},
  {"id":"inno_ent_267","name_ja":"起業家精神と社会関係資本","name_en":"Entrepreneurship and Social Capital","definition":"Burt（1992）の構造的穴理論とPutnam（1993）の社会関係資本論を起業家研究に応用した研究。橋渡し型ネットワーク（bridging ties）は情報多様性と機会認識を促進し、結束型ネットワーク（bonding ties）は資源動員と信頼構築に有利。Aldrich & Zimmer（1986）が起業家的ネットワーク研究の先駆的枠組みを提示した。","impact_summary":"起業家のネットワーク戦略と社会的埋め込みの重要性を理論化し、メンタリング・ネットワーキングプログラムの設計に応用された。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"ネットワーク論的起業家論","era_start":1992,"schumpeter_layer":"ミクロ","innovation_type":"ネットワークイノベーション","cognitive_mechanism":"橋渡しネットワークによる情報アービトラージ","key_researchers":["Howard Aldrich","Ronald Burt","Robert Putnam"],"key_works":["Entrepreneurship Through Social Networks (1986)","Structural Holes (1992)"],"keywords_ja":"社会関係資本,ネットワーク,橋渡し型,結束型,起業家","keywords_en":"social capital,network,bridging ties,bonding ties,entrepreneurship"},
  {"id":"inno_ent_268","name_ja":"フィンテックスタートアップの起業家精神","name_en":"Fintech Startup Entrepreneurship","definition":"金融サービスのデジタル革新を推進するフィンテックスタートアップの起業家精神研究。Stripe、Robinhood、Revolut、PayPayが代表事例。規制サンドボックス（英国FCA、日本金融庁）、オープンバンキングAPI、ブロックチェーン応用が制度的文脈を形成する。伝統的金融機関との「協調的競合（coopetition）」戦略と規制リスク管理が中心テーマ。","impact_summary":"金融システムへの技術起業家参入メカニズムを解明し、金融包摂と規制革新の政策論議を推進した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"金融技術イノベーション","cognitive_mechanism":"規制の隙間の機会認識と規制対応戦略","key_researchers":["Robert Wardrop","Bryan Zhang","Raghavendra Rau"],"key_works":["The Global Fintech Report (2015)","Disrupting Finance (2019)"],"keywords_ja":"フィンテック,規制サンドボックス,オープンバンキング,金融包摂","keywords_en":"fintech,regulatory sandbox,open banking,financial inclusion"},
  {"id":"inno_ent_269","name_ja":"ヘルスケアスタートアップの起業家精神","name_en":"Healthcare Startup Entrepreneurship","definition":"医療・ヘルスケア分野でのスタートアップが直面する固有の起業課題：FDA承認サイクル（平均12年）、保険償還（リンバースメント）の複雑さ、臨床エビデンス要件、医療ネットワークの慣性。デジタルヘルス（遠隔医療、ウェアラブル、AI診断）が規制環境を変えつつある。Andreessen HorowitzのBio Fundや専門健康系VCの投資戦略が研究される。","impact_summary":"医療イノベーションの商業化の独自ロジックを解明し、ヘルステックスタートアップ支援の専門知識を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"医療技術イノベーション","cognitive_mechanism":"規制環境適応と臨床エビデン構築","key_researchers":["Luke Timmerman","Bob Kocher","Christina Farr"],"key_works":["The Digital Health Revolution (2020)","Startup Health Insights Reports"],"keywords_ja":"ヘルスケアスタートアップ,デジタルヘルス,FDA,ヘルステック","keywords_en":"healthcare startup,digital health,FDA,healthtech"},
  {"id":"inno_ent_270","name_ja":"エドテックスタートアップ","name_en":"EdTech Startup Entrepreneurship","definition":"教育技術スタートアップの起業家精神。Coursera、Duolingo、Khan Academy、Udemyが代表事例。公教育市場への参入障壁（調達手続、教員組合、カリキュラム規制）とB2C（学習者直接）、B2B（企業向け）、B2G（政府・学校向け）の市場選択戦略が研究される。COVID-19によるEdTech需要急増（2020）とその後の利用率低下（learning loss）も分析対象。","impact_summary":"教育のデジタル変革における起業家の役割を記述し、エドテック投資と政策の相互作用を研究した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2012,"schumpeter_layer":"ミクロ","innovation_type":"教育技術イノベーション","cognitive_mechanism":"ユーザー動機と習慣形成の教育的設計","key_researchers":["Michael Horn","Clayton Christensen","Daphne Koller"],"key_works":["Disrupting Class (2008)","The Online Learning Revolution (2013)"],"keywords_ja":"エドテック,Coursera,教育のデジタル化,学習管理システム","keywords_en":"edtech,Coursera,digital education,LMS"},
  {"id":"inno_ent_271","name_ja":"宇宙スタートアップ（NewSpace）","name_en":"NewSpace Startup Entrepreneurship","definition":"民間宇宙産業（NewSpace）の起業家精神研究。SpaceX（Elon Musk）、Blue Origin（Jeff Bezos）、Planet Labs等が先駆的事例。再利用可能ロケット、小型衛星コンステレーション、宇宙旅行など技術革新が民間参入を可能にした。米国FAA Commercial Space規制、NASAのCCDev（商業乗員開発）プログラムが制度的背景。宇宙企業家精神の動機・挑戦・投資論理が研究される。","impact_summary":"政府独占産業への民間起業家参入モデルを確立し、宇宙技術の商業化と低コスト化を加速した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"宇宙技術イノベーション","cognitive_mechanism":"ミッション駆動のリスク選好と長期資本需要","key_researchers":["Elon Musk","Jeff Foust","Ryan Mayer"],"key_works":["Reusability: The Key to Making Human Life Multi-Planetary (2017)","Space: The Next Trillion Dollar Economy (2019)"],"keywords_ja":"NewSpace,SpaceX,小型衛星,再利用ロケット,宇宙起業","keywords_en":"NewSpace,SpaceX,smallsat,reusable rocket,space entrepreneurship"},
  {"id":"inno_ent_272","name_ja":"アグリテックスタートアップ","name_en":"AgriTech Startup Entrepreneurship","definition":"農業・食料システムの技術革新を推進するアグリテックスタートアップの起業家精神。精密農業（ドローン・IoTセンサー）、代替タンパク（Impossible Foods、Beyond Meat）、垂直農業（AeroFarms）、農業マーケットプレイス（インドのAgriBazaar）が代表事例。農家との信頼構築、農村インフラ制約、食品安全規制が主要課題。気候変動と食料安全保障の危機意識が起業動機として機能している。","impact_summary":"食料システムのイノベーションを起業家精神研究の対象として確立し、サステナブル農業への技術転換を促進した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"技術起業家論","era_start":2012,"schumpeter_layer":"ミクロ","innovation_type":"農業技術イノベーション","cognitive_mechanism":"農業現場ニーズと技術可能性のマッチング","key_researchers":["Rob Leclerc","Tom Barrat","AgFunder team"],"key_works":["AgFunder AgriFoodTech Investing Report (annual)","The Future of Food (2015)"],"keywords_ja":"アグリテック,精密農業,代替タンパク,垂直農業","keywords_en":"agritech,precision agriculture,alternative protein,vertical farming"},
  {"id":"inno_ent_273","name_ja":"ソーシャルベンチャーの法的形態","name_en":"Legal Forms for Social Ventures","definition":"社会的ミッションと商業活動を組み合わせた組織の法的・ガバナンス形態の研究。米国のL3C（Low-Profit Limited Liability Company）、Benefit Corporation（BCorp）、英国のCIC（Community Interest Company）、日本の社会的企業形態が比較研究される。ミッション保護（mission lock）と資本調達容易性のトレードオフが設計の中心課題。","impact_summary":"社会的ミッションと資本市場の制度的両立を可能にし、インパクト投資との接続を促進した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"社会的起業家論","era_start":2008,"schumpeter_layer":"メゾ","innovation_type":"制度・法的イノベーション","cognitive_mechanism":"ダブルボトムラインのガバナンス設計","key_researchers":["Dana Brakman Reiser","William Clark","Kyle Westaway"],"key_works":["Benefit Corporations (2012)","Social Enterprise Law (2014)"],"keywords_ja":"BCorp,L3C,ソーシャルベンチャー,ミッション保護,CIC","keywords_en":"BCorp,L3C,social venture,mission lock,CIC"},
  {"id":"inno_ent_274","name_ja":"起業家精神と幸福感研究","name_en":"Entrepreneurship and Well-Being Research","definition":"起業家活動が主観的幸福感（SWB）・精神的健康・仕事満足感に与える影響の実証研究。自律性・自己実現・意味への欲求が満たされる反面、不確実性・長時間労働・孤独感・経済的不安定が精神健康リスクとなる。Freeman et al.（2015）はシリコンバレー起業家に高率のうつ・双極性障害を報告。「起業家的情熱」の持続可能性と燃え尽き症候群の研究が進む。","impact_summary":"起業家のメンタルヘルス問題を可視化し、スタートアップ支援プログラムへの心理的サポート組み込みを促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"行動的起業家論","era_start":2009,"schumpeter_layer":"ミクロ","innovation_type":"ウェルビーイングイノベーション","cognitive_mechanism":"自律性動機と不確実性ストレスの相互作用","key_researchers":["Michael Freeman","Johan Wiklund","Melissa Cardon"],"key_works":["Are Entrepreneurs Touched with Fire? (2015)","Entrepreneurial Well-Being (2019)"],"keywords_ja":"起業家,幸福感,メンタルヘルス,情熱,燃え尽き","keywords_en":"entrepreneurship,well-being,mental health,passion,burnout"},
  {"id":"inno_ent_275","name_ja":"起業家精神教育のKibbutz効果","name_en":"Kibbutz Effect in Entrepreneurship Education","definition":"イスラエルのキブツ（集団農場）出身者が高い起業家性を示す現象を通じた、共同体的子育て・集団責任・実践的問題解決経験と起業家精神の関係研究。Lerner et al.によりキブツ出身者の起業率・企業成長が高いことが示され、コミュニティ起業教育の有効性を支持する事例となった。","impact_summary":"コミュニティ環境が起業家的資質を形成するメカニズムを実証し、起業家教育設計の社会的文脈重要性を示した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家教育論","era_start":2001,"schumpeter_layer":"ミクロ","innovation_type":"教育・コミュニティイノベーション","cognitive_mechanism":"共同体的学習と問題解決経験の累積","key_researchers":["Miri Lerner","Avraham Shoham","Shaked Gilboa"],"key_works":["From Collective to Corporate (2001)","Kibbutz Entrepreneurship (2007)"],"keywords_ja":"起業家教育,キブツ,コミュニティ学習,イスラエル","keywords_en":"entrepreneurship education,kibbutz,community learning,Israel"},
  {"id":"inno_ent_276","name_ja":"ハーバード大学起業家エコシステム","name_en":"Harvard University Entrepreneurship Ecosystem","definition":"ハーバード大学を中心に形成された起業家エコシステムの研究。HBS（ハーバードビジネススクール）の起業家教育（Baker Foundation、Rock Accelerator）、H-Lab、Innovation Lab等のインフラ、FB（Facebook）・Reddit・Dropboxなど著名卒業生の輩出実績が分析される。プロフェッショナル育成（MBA）を通じた起業家輩出モデルとスタンフォードとの比較も重要テーマ。","impact_summary":"大学エコシステムモデルの多様性（STEM型スタンフォードvs文理型ハーバード）を示し、大学イノベーション政策の参照事例となった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":1960,"schumpeter_layer":"メゾ","innovation_type":"教育・エコシステムイノベーション","cognitive_mechanism":"エリートネットワークと起業機会の非対称的アクセス","key_researchers":["William Sahlman","Howard Stevenson","Noam Wasserman"],"key_works":["The Founders Dilemmas (2012)","Entrepreneurial Management (2008)"],"keywords_ja":"ハーバード,起業家エコシステム,HBS,Rock Accelerator","keywords_en":"Harvard,entrepreneurship ecosystem,HBS,Rock Accelerator"},
  {"id":"inno_ent_277","name_ja":"MIT起業家エコシステム","name_en":"MIT Entrepreneurship Ecosystem","definition":"MITが形成する世界屈指の起業家エコシステム研究。Fano and Kling（2002）等はMIT卒業生・教員創業企業が毎年3万社以上の雇用と2兆ドルの売上を創出すると推計した。MIT Deshpande Center、Martin Trust Center、Lincoln Labの技術移転が出口。STEM＋ビジネス教育の融合、DeepTech偏重の資金調達文化が特徴。","impact_summary":"理工系大学からの起業家輩出モデルを確立し、大学発ディープテックスタートアップの育成理論を提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":1950,"schumpeter_layer":"メゾ","innovation_type":"大学発イノベーション","cognitive_mechanism":"技術的優位性とベンチャーキャピタルの融合","key_researchers":["Edward Roberts","Charles Eesley","Martin West"],"key_works":["Entrepreneurship in MIT (2011)","MIT: A Living Laboratory for Entrepreneurship"],"keywords_ja":"MIT,技術移転,ディープテック,大学発スタートアップ","keywords_en":"MIT,technology transfer,deep tech,university startup"},
  {"id":"inno_ent_278","name_ja":"起業家精神の進化論的視点","name_en":"Evolutionary Perspective on Entrepreneurship","definition":"Nelson & Winter（1982）の進化経済学を起業家研究に応用した視点。起業家的ルーティンの変異（variation）・選択（selection）・保持（retention）プロセスが産業進化を駆動するという枠組みを提供する。新企業参入が既存技術・組織ルーティンへの選択圧となり、産業の技術的多様性を維持する役割を持つ。Aldrich & Martínezの「人口生態学的アプローチ」も関連する。","impact_summary":"起業家精神を産業進化のメカニズムとして位置づけ、創業率・廃業率と産業技術変革の関係を理論化した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"進化経済学","era_start":1982,"schumpeter_layer":"マクロ","innovation_type":"進化的イノベーション","cognitive_mechanism":"変異と選択の連続的プロセス","key_researchers":["Richard Nelson","Sidney Winter","Howard Aldrich"],"key_works":["An Evolutionary Theory of Economic Change (1982)","Organizations Evolving (1999)"],"keywords_ja":"進化経済学,起業家精神,変異-選択-保持,産業進化","keywords_en":"evolutionary economics,entrepreneurship,variation-selection-retention,industry evolution"},
  {"id":"inno_ent_279","name_ja":"資源ベース視点と起業家精神","name_en":"Resource-Based View and Entrepreneurship","definition":"Barney（1991）のRBV（資源ベース視点）を起業家研究に接続し、ベンチャー企業の持続的競争優位の源泉を分析する枠組み。希少・模倣困難・代替不可能（VRIN）な資源がどのように新規ベンチャーに蓄積されるか、ブートストラップ（自己資金型資源獲得）、資源コンフィギュレーション（Brush et al.）が研究される。動的能力（Teece）との統合も進む。","impact_summary":"ベンチャー企業の競争優位形成メカニズムを体系化し、スタートアップ戦略論の理論的基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"資源ベース論","era_start":1991,"schumpeter_layer":"ミクロ","innovation_type":"戦略イノベーション","cognitive_mechanism":"資源の識別・獲得・構成能力","key_researchers":["Jay Barney","Candida Brush","Lowell Busenitz"],"key_works":["Firm Resources and Sustained Competitive Advantage (1991)","Resources in the Emerging Firm (2001)"],"keywords_ja":"資源ベース視点,RBV,VRIN,ブートストラップ,スタートアップ戦略","keywords_en":"RBV,resource-based view,VRIN,bootstrapping,startup strategy"},
  {"id":"inno_ent_280","name_ja":"ダイナミックケイパビリティと起業家精神","name_en":"Dynamic Capabilities and Entrepreneurship","definition":"Teece et al.（1997）のダイナミックケイパビリティを起業家的文脈に応用した研究。感知（sensing）→捕捉（seizing）→再構成（reconfiguring）の3能力が新興企業の適応・成長を説明する。ピボット戦略はダイナミックケイパビリティの実践形態として理論化できる。創業チームの認知的柔軟性と組織学習能力が動的能力の源泉として分析される。","impact_summary":"環境変化への適応能力を起業家論に組み込み、スタートアップの成長軌道変更（ピボット）を理論的に説明した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"資源ベース論","era_start":1997,"schumpeter_layer":"ミクロ","innovation_type":"能力イノベーション","cognitive_mechanism":"環境感知と資源再配置の認知的柔軟性","key_researchers":["David Teece","Gary Pisano","Amy Shuen"],"key_works":["Dynamic Capabilities and Strategic Management (1997)","Dynamic Capabilities: Understanding Strategic Change (2009)"],"keywords_ja":"ダイナミックケイパビリティ,感知-捕捉-再構成,ピボット,適応","keywords_en":"dynamic capabilities,sensing-seizing-reconfiguring,pivot,adaptation"},
  {"id":"inno_ent_281","name_ja":"スタートアップの組織構造と成長","name_en":"Startup Organizational Structure and Growth","definition":"創業初期から成長段階への組織変化（構造変革、採用、管理システム導入）の研究。GreinerのGrowth Curve（創造性→方向性→委任→調整→協働の5段階危機）の新興企業への適用。Blitzscalingでは組織スケールよりスピードを優先するため、カオスを受け入れた組織設計が求められる。創業者モード（Founder Mode）対マネジャーモードのトランジションが経営危機を生む「設立者の罠」も研究対象。","impact_summary":"創業後の組織成長危機を予測し、スケーリングフェーズの組織設計・人事戦略に実践的指針を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"組織論的起業家論","era_start":1972,"schumpeter_layer":"ミクロ","innovation_type":"組織イノベーション","cognitive_mechanism":"創業者の権力移行と組織官僚制化への抵抗","key_researchers":["Larry Greiner","Noam Wasserman","Ben Horowitz"],"key_works":["Evolution and Revolution as Organizations Grow (1972)","The Founders Dilemmas (2012)"],"keywords_ja":"組織成長,創業者の罠,Greiner曲線,スケーリング","keywords_en":"organizational growth,founder's dilemma,Greiner curve,scaling"},
  {"id":"inno_ent_282","name_ja":"スタートアップの採用と人材戦略","name_en":"Startup Hiring and Talent Strategy","definition":"人材獲得競争が激化する中でのスタートアップの採用・報酬・組織文化設計の研究。ストックオプション（ESOP）による報酬設計、「Aプレーヤー採用（Steve Jobs原則）」、カルチャーフィット対スキルフィットのトレードオフ、リモートワーク時代の採用地域多様化が研究される。Patty McCordの「Netflix Culture Deck」が組織文化設計の代表的実践事例として研究された。","impact_summary":"人材を最重要経営資源として位置づけるスタートアップ人事論を体系化し、HRテックの発展に理論基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"組織論的起業家論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"人材・組織イノベーション","cognitive_mechanism":"文化的同質性と多様性のバランス","key_researchers":["Patty McCord","Ben Horowitz","Jeff Hyman"],"key_works":["Powerful: Building a Culture of Freedom and Responsibility (2018)","The Hard Thing About Hard Things (2014)"],"keywords_ja":"スタートアップ採用,ESOP,カルチャーフィット,Netflix Culture","keywords_en":"startup hiring,ESOP,culture fit,Netflix Culture Deck"},
  {"id":"inno_ent_283","name_ja":"アフリカ起業家精神と「リープフロッグ」","name_en":"African Entrepreneurship and Leapfrog Innovation","definition":"インフラ未整備のアフリカ諸国でモバイル技術を活用して先進国の発展段階を飛び越える「リープフロッグ型イノベーション」を推進する起業家精神。M-Pesa（ケニア）、Flutterwave（ナイジェリア）、Jumia（アフリカのAmazon）が代表事例。「次の10億人」市場をターゲットとするスタートアップの動機・障壁・成功要因が研究される。","impact_summary":"インフラ欠如を技術で克服するリープフロッグ現象を起業家論的に説明し、グローバルサウスの技術起業研究を活性化した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"新興市場起業家論","era_start":2008,"schumpeter_layer":"ミクロ","innovation_type":"リープフロッグイノベーション","cognitive_mechanism":"インフラ制約の機会への転換","key_researchers":["Erik Hersman","Karim Sy","Leila Janah"],"key_works":["Africa's Tech Revolution (2018)","M-Pesa: Mobile Money for the Unbanked (2012)"],"keywords_ja":"アフリカ,リープフロッグ,M-Pesa,モバイルマネー,次の10億人","keywords_en":"Africa,leapfrog,M-Pesa,mobile money,next billion users"},
  {"id":"inno_ent_284","name_ja":"ラテンアメリカ起業家精神","name_en":"Latin American Entrepreneurship","definition":"ブラジル、メキシコ、コロンビア等のラテンアメリカ起業家エコシステムの発展研究。Nubank（ブラジル）、Mercado Libre（アルゼンチン）、Rappi（コロンビア）等のユニコーンが輩出。LAVCA（ラテンアメリカVC協会）のデータが基盤。文化的要因（家族主義、リスク回避）、制度的不安定性（高インフレ、法的不確実性）が起業環境を形成する独自の文脈が分析される。","impact_summary":"新興市場における起業エコシステム形成の地域多様性を記述し、投資家・政策立案者のラテンアメリカ理解を深めた。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"比較起業家論","era_start":2010,"schumpeter_layer":"メゾ","innovation_type":"新興市場イノベーション","cognitive_mechanism":"制度的不確実性への適応と機会発見","key_researchers":["Gonzalo Rivas","Juan Jose Llisterri","LAVCA researchers"],"key_works":["Latin America Venture Capital Report (annual)","Entrepreneurship in Latin America (2014)"],"keywords_ja":"ラテンアメリカ,Nubank,Mercado Libre,新興市場起業","keywords_en":"Latin America,Nubank,Mercado Libre,emerging market entrepreneurship"},
  {"id":"inno_ent_285","name_ja":"東南アジア起業家精神","name_en":"Southeast Asian Entrepreneurship","definition":"シンガポール、インドネシア、ベトナム、タイ等の東南アジア起業エコシステムの研究。Grab（シンガポール/マレーシア）、Gojek（インドネシア）、Sea Group、Tokopediaが代表的ユニコーン。スーパーアプリ戦略（複合機能集約）、銀行口座非保有人口への金融包摂、ASEANを一体として見る市場戦略が特徴。政府主導の起業支援（シンガポールEDB等）も分析される。","impact_summary":"東南アジア特有のスーパーアプリモデルと多言語・多国籍市場戦略を記述し、地域起業生態系研究を豊かにした。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"比較起業家論","era_start":2012,"schumpeter_layer":"メゾ","innovation_type":"新興市場イノベーション","cognitive_mechanism":"地域特性への適応と多市場同時展開","key_researchers":["Ming Tan","e27 research team","Temasek/Google SEA Economy Report authors"],"key_works":["e-Conomy SEA Report (annual)","Startup Genome Southeast Asia (2021)"],"keywords_ja":"東南アジア,スーパーアプリ,Grab,Gojek,ASEAN起業","keywords_en":"Southeast Asia,super app,Grab,Gojek,ASEAN entrepreneurship"},
  {"id":"inno_ent_286","name_ja":"起業家的リーダーシップ論","name_en":"Entrepreneurial Leadership Theory","definition":"起業家的ビジョンの構築・コミュニケーション・実行を担うリーダーシップの研究。Gupta et al.（2004）は起業家的リーダーシップを「仮定的将来（envisioned future）」の実現に向けてコラボレーションを促す能力と定義した。カリスマ的リーダーシップ（Jobs型）と変革型リーダーシップの起業家的文脈への適用、founder-CEOと外部CEOの移行問題が研究される。","impact_summary":"スタートアップ固有のリーダーシップ論を確立し、創業者から専門経営者へのトランジション管理の知見を蓄積した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家リーダーシップ論","era_start":2004,"schumpeter_layer":"ミクロ","innovation_type":"リーダーシップイノベーション","cognitive_mechanism":"ビジョンの具体化と組織へのコミットメント生成","key_researchers":["Vishal Gupta","Ian MacMillan","Gerry Yemen"],"key_works":["Entrepreneurial Leadership: Developing and Measuring a Cross-Cultural Construct (2004)","The Founder's Mentality (2016)"],"keywords_ja":"起業家的リーダーシップ,創業者,ビジョン,founder-CEO","keywords_en":"entrepreneurial leadership,founder,vision,founder-CEO transition"},
  {"id":"inno_ent_287","name_ja":"フラグメンテーション産業と起業","name_en":"Fragmented Industry Entrepreneurship","definition":"Porter（1980）が提唱したフラグメンテーション産業（規模の経済が働かず多数の小規模企業が競合する産業）での起業戦略研究。レストラン、建設、美容サービス等が典型例。テクノロジー（クラウド会計、予約システム、デジタルマーケティング）による中小企業支援スタートアップ（「垂直型SaaS」）が新たな起業機会として台頭している。","impact_summary":"フラグメンテーション産業向け技術スタートアップの機会を特定し、垂直型SaaSの投資理論を支えた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"産業組織論的起業家論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"産業組織イノベーション","cognitive_mechanism":"産業構造の非効率性の機会認識","key_researchers":["Michael Porter","Tomasz Tunguz","Christoph Janz"],"key_works":["Competitive Strategy (1980)","The SaaS Adventure (2019)"],"keywords_ja":"フラグメンテーション,垂直型SaaS,中小企業テック,産業構造","keywords_en":"fragmented industry,vertical SaaS,SMB tech,industry structure"},
  {"id":"inno_ent_288","name_ja":"起業家精神のダークサイド研究","name_en":"Dark Side of Entrepreneurship Research","definition":"起業家活動の負の側面：詐欺的起業（Theranos等）、搾取的ビジネスモデル、環境破壊、プラットフォーム独占等を研究する領域。Baumol（1990）の「生産的・非生産的・破壊的起業家精神」の分類が理論基盤。Wicked Entrepreneurship（悪質な起業家精神）、企業不正の組織的文化、起業家神話の批判的検討がテーマ。","impact_summary":"起業家精神の美化に批判的視点を提供し、規制・ガバナンス設計と起業家倫理教育に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"批判的起業家論","era_start":1990,"schumpeter_layer":"ミクロ","innovation_type":"倫理的・制度的イノベーション","cognitive_mechanism":"目的実現への過信と倫理的盲点","key_researchers":["William Baumol","Scott Shane","Susanne Doyle"],"key_works":["Entrepreneurship: Productive, Unproductive, and Destructive (1990)","The Dark Side of Entrepreneurship (2015)"],"keywords_ja":"起業家精神のダークサイド,Theranos,不正,破壊的起業家","keywords_en":"dark side entrepreneurship,Theranos,fraud,destructive entrepreneurship"},
  {"id":"inno_ent_289","name_ja":"起業家精神と持続可能性（SE）","name_en":"Sustainable Entrepreneurship","definition":"環境的・社会的持続可能性を核心的ミッションとする起業家精神（sustainable entrepreneurship）の研究。Hockerts & Wüstenhagen（2010）は「デビッド対ゴリアテ」ダイナミクスで小規模サステナビリティ起業家が業界規範を変えるメカニズムを分析した。サーキュラーエコノミー起業（廃棄物→資源化）、再生可能エネルギー起業がケース事例。SDGsとの接続も研究される。","impact_summary":"起業家精神を持続可能な発展の担い手として位置づけ、グリーン起業支援政策の理論基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"社会的起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"持続可能性イノベーション","cognitive_mechanism":"サステナブル機会の認識と事業化動機","key_researchers":["Kai Hockerts","Rolf Wüstenhagen","Tobias Hahn"],"key_works":["Greening Goliaths versus Emerging Davids (2010)","Business Models for Sustainability (2017)"],"keywords_ja":"サステナブル起業家精神,サーキュラーエコノミー,SDGs,グリーン起業","keywords_en":"sustainable entrepreneurship,circular economy,SDGs,green startup"},
  {"id":"inno_ent_290","name_ja":"起業家精神のナラティブ研究","name_en":"Narrative Research in Entrepreneurship","definition":"起業家の経験・意味形成・アイデンティティ構築を物語（ナラティブ）の視点から研究する質的アプローチ。Downing（2005）はストーリーテリングが外部ステークホルダーを動員する「社会的-認知的」道具であると論じた。ピッチングのナラティブ構造（英雄の旅、問題-解決、変革物語）と投資獲得の関係も研究される。","impact_summary":"起業家研究における定量・実証偏重に質的・解釈的視点をもたらし、ナラティブピッチング研究の基盤となった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"解釈的起業家論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"コミュニケーションイノベーション","cognitive_mechanism":"ナラティブによる意味形成と正当性獲得","key_researchers":["Stephen Downing","William Gartner","Maija Renko"],"key_works":["The Social Construction of Entrepreneurship (2005)","Using Social Network Analysis (2011)"],"keywords_ja":"ナラティブ,物語,起業家,ピッチング,意味形成","keywords_en":"narrative,storytelling,entrepreneurship,pitching,sensemaking"},
  {"id":"inno_ent_291","name_ja":"先住民起業家精神","name_en":"Indigenous Entrepreneurship","definition":"先住民族・少数民族の起業家精神研究。Anderson & Dana（2011）は先住民の起業を「個人的利益より共同体の福祉」を中心とする「集団的起業家精神」として記述した。土地権・知的財産権・文化的資産の商業化倫理、政府承認の法的地位が特有の制度的文脈を形成する。ニュージーランドのマオリビジネス、北米先住民カジノ経営が研究事例。","impact_summary":"非西洋的起業家精神の多様性を記述し、起業家研究の文化的偏向への批判的視点を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"文化的起業家論","era_start":2002,"schumpeter_layer":"ミクロ","innovation_type":"文化的・社会的イノベーション","cognitive_mechanism":"集団的意思決定と共同体的価値観","key_researchers":["Robert Anderson","Leo Dana","Tui McKeown"],"key_works":["Indigenous Entrepreneurship (2011)","Entrepreneurship and the American Indian (2000)"],"keywords_ja":"先住民起業家精神,集団的起業,マオリ,文化的資産","keywords_en":"indigenous entrepreneurship,collective entrepreneurship,Maori,cultural assets"},
  {"id":"inno_ent_292","name_ja":"高齢者起業家精神","name_en":"Senior Entrepreneurship","definition":"50歳以上の起業家（シニア起業家）の特性・動機・成功要因を研究する領域。GEMデータでは50〜64歳の起業活動が増加傾向にある。経験・ネットワーク・財務的安定が有利に働く一方、テクノロジー適応・エネルギー・長期コミットメントが課題。定年退職後の「第3の人生」起業や、高齢者ニーズを高齢者自身が解決するリビングラボ型事業が研究される。","impact_summary":"超高齢社会における起業家精神の新フロンティアを開拓し、シルバースタートアップ支援政策の理論基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"ライフコース起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"社会イノベーション","cognitive_mechanism":"経験知の活用と新起業動機の形成","key_researchers":["Siri Terjesen","Shaker Zahra","Donald Kuratko"],"key_works":["Senior Entrepreneurship and Technology (2012)","The Silver Economy (2020)"],"keywords_ja":"シニア起業家,高齢者,第三の人生,リビングラボ","keywords_en":"senior entrepreneurship,older entrepreneurs,silver economy,living lab"},
  {"id":"inno_ent_293","name_ja":"若者起業家精神（ユース起業家精神）","name_en":"Youth Entrepreneurship","definition":"35歳以下の若者起業家の動機・行動・障壁を研究する領域。OECD・EU・ILOの若者雇用対策として起業家教育が位置づけられる文脈で研究が蓄積された。デジタルネイティブ世代の特徴（即時フィードバック欲求・リスク許容・SNS活用）が独自の起業スタイルを形成する。Z世代起業家の価値観（目的意識・サステナビリティ重視）が経営判断に与える影響も研究される。","impact_summary":"若者失業対策と起業家精神育成の政策接合を支持する実証基盤を提供し、起業家教育の早期化を後押しした。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家教育論","era_start":2004,"schumpeter_layer":"ミクロ","innovation_type":"社会・経済イノベーション","cognitive_mechanism":"デジタルネイティブ特有の機会認識とリスク選好","key_researchers":["Dana Redford","Alain Fayolle","Tony Verzat"],"key_works":["Handbook of Research in Entrepreneurship Education (2005)","Youth Entrepreneurship (OECD 2012)"],"keywords_ja":"若者起業家,ユース起業,Z世代,起業家教育","keywords_en":"youth entrepreneurship,young entrepreneurs,Gen Z,entrepreneurship education"},
  {"id":"inno_ent_294","name_ja":"難民・移民起業家精神","name_en":"Refugee and Migrant Entrepreneurship","definition":"難民・強制移住者の起業家精神研究。資産・ネットワーク・言語の喪失という極端な制約下での起業行動が分析される。トルコのシリア難民起業家、欧州への難民起業支援プログラム（Kiron、Social Innovation Exchange）が事例。「ブリコラージュ（手持ち資源の創造的組み合わせ）」が制約下起業の主要メカニズムとして機能する。","impact_summary":"極限的制約下での起業家精神を研究し、難民統合政策に起業支援を組み込む政策議論を促進した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"移民起業家論","era_start":2015,"schumpeter_layer":"ミクロ","innovation_type":"社会包摂イノベーション","cognitive_mechanism":"ブリコラージュと制約の機会転換","key_researchers":["Marlous van Waijenburg","Ted Baker","Friederike Welter"],"key_works":["Doing More with Less: Constraints and Bricolage (2005)","Refugee Entrepreneurship (2019)"],"keywords_ja":"難民起業家,ブリコラージュ,強制移住,社会統合","keywords_en":"refugee entrepreneurship,bricolage,forced migration,social integration"},
  {"id":"inno_ent_295","name_ja":"オープンソース起業家精神","name_en":"Open Source Entrepreneurship","definition":"オープンソースソフトウェア（OSS）を基盤とするビジネスモデル構築の起業家精神研究。Red Hat、Canonical（Ubuntu）、Elastic、HashiCorpがOSSを核とした商業事業の代表事例。オープンコアモデル（無償版＋有償エンタープライズ版）、サポート・コンサルティング収益化、クラウドホスト提供の3ビジネスモデルが分析される。Apache、Linux Foundationのエコシステムとの関係も研究対象。","impact_summary":"OSS商業化の複数モデルを整理し、コモンズ（共有資源）を基盤とした起業戦略論を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"プラットフォーム論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"オープンイノベーション","cognitive_mechanism":"コモンズ活用と差別化収益化の共存","key_researchers":["Yochai Benkler","Steven Weber","Matthew Aslett"],"key_works":["The Wealth of Networks (2006)","The Success of Open Source (2004)"],"keywords_ja":"オープンソース,OSSビジネスモデル,オープンコア,Linux","keywords_en":"open source,OSS business model,open core,Linux"},
  {"id":"inno_ent_296","name_ja":"ゲーミフィケーションと起業家精神","name_en":"Gamification and Entrepreneurship","definition":"ゲーム要素（ポイント、バッジ、リーダーボード、ミッション）を起業プロセスや起業家教育に適用する研究。スタートアップゲーム（Startup Simulator等）の教育効果、ハッカソン（Hackathon）の起業家精神育成機能、クラウドソーシングのゲーム的設計が研究される。Google、Yahoo!、社内インキュベーションでのゲーミフィケーション活用事例も分析される。","impact_summary":"学習動機と起業行動の促進にゲーム的設計を活用する可能性を示し、起業家教育の方法論を多様化した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家教育論","era_start":2011,"schumpeter_layer":"ミクロ","innovation_type":"教育・行動イノベーション","cognitive_mechanism":"内発的動機と即時フィードバックによる行動促進","key_researchers":["Karl Kapp","Jan Herrington","Sebastian Deterding"],"key_works":["The Gamification of Learning (2012)","Gamification and Education (2013)"],"keywords_ja":"ゲーミフィケーション,ハッカソン,起業家教育,行動促進","keywords_en":"gamification,hackathon,entrepreneurship education,behavioral activation"},
  {"id":"inno_ent_297","name_ja":"フェムテック起業家精神","name_en":"FemTech Entrepreneurship","definition":"女性の健康・ウェルネス（月経、妊娠、更年期、性健康等）をテクノロジーで解決するフェムテック（FemTech）スタートアップの研究。Ida Tinの造語（2016年）で市場規模は2025年に500億ドル超と推計。従来の医療・テック産業の男性偏重が解決されてこなかったニーズへの起業家的対応として研究される。FDA規制、保険適用、投資家の偏見が課題。","impact_summary":"女性健康市場の未充足ニーズを可視化し、ジェンダードイノベーションとフェミニスト起業家精神の実践例を提示した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"フェミニスト起業家論","era_start":2016,"schumpeter_layer":"ミクロ","innovation_type":"ジェンダードイノベーション","cognitive_mechanism":"ユーザー経験の当事者的洞察","key_researchers":["Ida Tin","Brittany Barreto","Charu Bahri"],"key_works":["FemTech: The Future of Women's Health (2019)","Redefining Women's Health (2021)"],"keywords_ja":"フェムテック,女性健康,ジェンダードイノベーション,FemTech","keywords_en":"FemTech,women's health,gendered innovation,femtech startups"},
  {"id":"inno_ent_298","name_ja":"スタートアップ法務と知財戦略","name_en":"Startup Legal and IP Strategy","definition":"スタートアップが創業初期から構築すべき法的基盤（設立形態、株主間合意書、雇用契約、知財登録）と知財戦略の研究。特許ポートフォリオ構築 vs オープンソース戦略の選択、非開示契約（NDA）の有効性、ソフトウェア特許の議論、商標・ブランド保護が主要テーマ。Patent Troll（特許侵害訴訟専門組織）への防衛戦略も研究される。","impact_summary":"知財戦略を創業初期からの競争優位構築要素として位置づけ、スタートアップ法務教育の標準化に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家法務論","era_start":1995,"schumpeter_layer":"ミクロ","innovation_type":"制度・法的イノベーション","cognitive_mechanism":"知的財産の価値評価と競争戦略への統合","key_researchers":["Clarisa Long","Robert Merges","Mark Lemley"],"key_works":["IP Strategy for Startups (2015)","Patent Failure (2008)"],"keywords_ja":"スタートアップ法務,知財戦略,特許,商標,NDA","keywords_en":"startup legal,IP strategy,patent,trademark,NDA"},
  {"id":"inno_ent_299","name_ja":"ストラテジック・アントレプレナーシップ","name_en":"Strategic Entrepreneurship","definition":"Hitt et al.（2001）が提唱した、機会探索（起業家的側面）と競争優位維持（戦略的側面）を統合する研究領域。スタートアップが長期的競争優位を構築しながら継続的に新機会を追求するための組織能力・リソース配分・リーダーシップが研究される。アンビデクスタリティ（探索と深耕の両立）の新興企業への適用が主要テーマ。","impact_summary":"戦略経営と起業家研究の統合を促進し、スタートアップから成長企業への移行期の経営論を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"戦略的起業家論","era_start":2001,"schumpeter_layer":"ミクロ","innovation_type":"戦略・経営イノベーション","cognitive_mechanism":"探索と深耕の同時追求（アンビデクスタリティ）","key_researchers":["Michael Hitt","Duane Ireland","Robert Hoskisson"],"key_works":["Strategic Entrepreneurship (2001)","Strategic Management: Competitiveness and Globalization (2019)"],"keywords_ja":"戦略的起業家精神,アンビデクスタリティ,競争優位,機会探索","keywords_en":"strategic entrepreneurship,ambidexterity,competitive advantage,opportunity pursuit"},
  {"id":"inno_ent_300","name_ja":"起業家精神とマクロ経済成長","name_en":"Entrepreneurship and Macroeconomic Growth","definition":"Schumpeter（1934）の創造的破壊理論から始まり、Aghion & Howittの内生的成長理論、Acemoglu et al.の制度的成長理論まで、起業家精神と国・地域レベルの経済成長の関係を分析する研究。Audretsch & Keilbach（2004）のKnowledge Spillover Theory（KSTE）がVenture Capitalと経済成長の実証的関係を確立した。","impact_summary":"起業家精神を国家経済成長の主要な決定要因として理論化し、起業家支援政策に経済学的正当性を与えた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"マクロ経済学的起業家論","era_start":1934,"schumpeter_layer":"マクロ","innovation_type":"経済成長イノベーション","cognitive_mechanism":"創造的破壊と知識スピルオーバーの経済成長エンジン","key_researchers":["David Audretsch","Max Keilbach","Zoltan Acs"],"key_works":["Entrepreneurship Capital and Economic Growth (2004)","The Knowledge Spillover Theory of Entrepreneurship (2009)"],"keywords_ja":"起業家精神,経済成長,KSTE,創造的破壊,内生的成長","keywords_en":"entrepreneurship,economic growth,KSTE,creative destruction,endogenous growth"},
]
conn = sqlite3.connect(DB)
c = conn.cursor()
inserted = skipped = 0
for r in records:
    try:
        c.execute("""INSERT INTO innovation_theory
            (id,name_ja,name_en,definition,impact_summary,subfield,category,
             school_of_thought,era_start,schumpeter_layer,innovation_type,
             cognitive_mechanism,key_researchers,key_works,keywords_ja,keywords_en)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (r["id"],r["name_ja"],r["name_en"],r["definition"],r["impact_summary"],
             r["subfield"],r["category"],r["school_of_thought"],r["era_start"],
             r["schumpeter_layer"],r["innovation_type"],r["cognitive_mechanism"],
             json.dumps(r["key_researchers"],ensure_ascii=False),
             json.dumps(r["key_works"],ensure_ascii=False),
             r["keywords_ja"],r["keywords_en"]))
        inserted += 1
    except sqlite3.IntegrityError:
        skipped += 1
conn.commit()
conn.close()
print(f"Inserted: {inserted}, Skipped: {skipped}")
